### RESP Protocol
```rust
/// RESP (REdis Serialization Protocol) codec.
pub struct RespCodec;

#[derive(Debug)]
pub enum RespValue {
    SimpleString(String),
    Error(String),
    Integer(i64),
    BulkString(Option<Bytes>),
    Array(Option<Vec<RespValue>>),
}

impl RespCodec {
    pub fn encode(value: &RespValue) -> Bytes {
        match value {
            RespValue::SimpleString(s) => format!("+{}\r\n", s).into(),
            RespValue::Error(e) => format!("-{}\r\n", e).into(),
            RespValue::Integer(i) => format!(":{}\r\n", i).into(),
            RespValue::BulkString(Some(b)) => {
                format!("${}\r\n", b.len()) + &String::from_utf8_lossy(b) + "\r\n"
            }
            RespValue::BulkString(None) => "$-1\r\n".into(),
            RespValue::Array(Some(arr)) => {
                let mut buf = format!("*{}\r\n", arr.len());
                for v in arr {
                    buf.push_str(&Self::encode(v));
                }
                buf.into()
            }
            RespValue::Array(None) => "*-1\r\n".into(),
        }
    }

    pub fn decode(data: &[u8]) -> Result<RespValue, RespError>;
}
```

### Commands API
```rust
impl RedisClient {
    /// GET key
    pub async fn get(&self, cx: &Cx, key: &str) -> Outcome<Option<Bytes>, RedisError> {
        self.cmd(cx, &["GET", key]).await?.as_bulk()
    }

    /// SET key value [EX seconds]
    pub async fn set(
        &self,
        cx: &Cx,
        key: &str,
        value: &[u8],
        ttl: Option<Duration>,
    ) -> Outcome<(), RedisError> {
        if let Some(ttl) = ttl {
            self.cmd(cx, &["SET", key, value, "EX", &ttl.as_secs().to_string()]).await?;
        } else {
            self.cmd(cx, &["SET", key, value]).await?;
        }
        Ok(())
    }

    /// DEL key [key ...]
    pub async fn del(&self, cx: &Cx, keys: &[&str]) -> Outcome<i64, RedisError>;

    /// INCR key
    pub async fn incr(&self, cx: &Cx, key: &str) -> Outcome<i64, RedisError>;

    /// EXPIRE key seconds
    pub async fn expire(&self, cx: &Cx, key: &str, seconds: u64) -> Outcome<bool, RedisError>;

    /// HGET hash field
    pub async fn hget(&self, cx: &Cx, hash: &str, field: &str) -> Outcome<Option<Bytes>, RedisError>;

    /// HSET hash field value
    pub async fn hset(&self, cx: &Cx, hash: &str, field: &str, value: &[u8]) -> Outcome<(), RedisError>;

    /// Execute raw command.
    pub async fn cmd(&self, cx: &Cx, args: &[&str]) -> Outcome<RespValue, RedisError> {
        cx.checkpoint()?;
        let conn = self.get(cx).await?;
        let request = RespValue::Array(Some(
            args.iter().map(|s| RespValue::BulkString(Some(s.as_bytes().into()))).collect()
        ));
        conn.send(RespCodec::encode(&request)).await?;
        conn.recv().await
    }
}
```

